// Parse RSS feeds and extract trending topics
const trendsXml = $('Fetch Google Trends RSS').first().json.data || '';
const newsXml = $('Fetch News RSS').first().json.data || '';

// Simple XML title extraction
function extractTitles(xml) {
  const titles = [];
  const regex = /<title[^>]*><!\[CDATA\[(.+?)\]\]><\/title>|<title[^>]*>([^<]+)<\/title>/g;
  let match;
  while ((match = regex.exec(xml)) !== null) {
    const title = match[1] || match[2];
    if (title && title.length > 5 && !title.includes('Google') && !title.includes('RSS')) {
      titles.push(title.trim());
    }
  }
  return titles;
}

const trendTopics = extractTitles(trendsXml).slice(0, 10);
const newsTopics = extractTitles(newsXml).slice(0, 10);

// Evergreen topics database
const evergreenTopics = [
  'похудение без диет',
  'боль в суставах лечение',
  'давление нормализовать',
  'пенсия повышение',
  'заработок в интернете',
  'омоложение лица',
  'грибок ногтей лечение',
  'зрение восстановить',
  'сахарный диабет новое лечение',
  'варикоз убрать'
];

// Combine all topics
const allTopics = [
  ...trendTopics.map(t => ({ topic: t, source: 'google_trends' })),
  ...newsTopics.map(t => ({ topic: t, source: 'news_rss' })),
  ...evergreenTopics.map(t => ({ topic: t, source: 'evergreen' }))
];

// Pick up to 5 topics for this cycle
const selectedTopics = allTopics
  .sort(() => Math.random() - 0.5)
  .slice(0, 5);

return selectedTopics.map(t => ({ json: t }));

const response = $input.first().json;
const topic = $('Parse & Select Trends').first().json.topic;
const source = $('Parse & Select Trends').first().json.source;

// Extract titles from Claude response
let titles = [];
try {
  const content = response.content?.[0]?.text || response.text || '';
  // Try to parse JSON array from response
  const jsonMatch = content.match(/\[([\s\S]*?)\]/);
  if (jsonMatch) {
    titles = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  // Fallback: split by newlines
  const content = response.content?.[0]?.text || '';
  titles = content.split('\n').filter(l => l.trim().length > 20).map(l => l.replace(/^[\d.\-*]+\s*/, '').trim());
}

// Filter valid titles (30-120 chars)
titles = titles.filter(t => t && t.length >= 30 && t.length <= 120);

return titles.map(title => ({
  json: {
    trend_topic: topic,
    trend_source: source,
    title: title,
    status: 'pending'
  }
}));

