INSERT INTO content_queue (trend_source, trend_topic, generated_titles, status, priority)
VALUES (
  '{{ $json.trend_source }}',
  '{{ $json.trend_topic }}',
  '{{ JSON.stringify([$json.title]) }}'::jsonb,
  'pending',
  {{ $json.trend_source === 'google_trends' ? 2 : ($json.trend_source === 'news_rss' ? 1 : 0) }}
)
ON CONFLICT DO NOTHING;
